  ('judicial-cf446b4c-moex-00294', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法第185條之3危險駕駛罪，下列敘述何者正確？', '["依據立法理由所述，刑法第185條之3危險駕駛罪為實害犯", "本罪之成立，應以事實上對其他用路人造成具體危險為要件", "犯危險駕駛罪，因而致人於死者，成立本條第2項之加重結果犯", "過失而犯危險駕駛罪，亦予處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
