  ('judicial-cf446b4c-moex-00299', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲掌握乙公司非法傾倒廢棄物之事證，要求封口費新臺幣30萬元，否則將告發，乙擔心己恐遭追訴， 只好花錢消災。甲成立何罪？', '["恐嚇取財罪", "強盜取財罪", "竊盜罪", "侵占罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
