  ('judicial-cf446b4c-moex-00302', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲開車不慎撞及騎士A受傷倒地，A頭臚破裂且昏迷不醒，甲擔心刑責，乃加速逃逸，對A棄置不 顧。A經路人立即送醫急救，因已有致命傷勢，到醫院前已死亡。有關甲所成立之罪名，下列敘述何 者正確？', '["僅成立遺棄致死罪一罪", "僅成立發生交通事故逃逸致死罪一罪", "過失致死罪與發生交通事故逃逸罪，兩罪數罪併罰", "過失致傷罪與過失致死罪，兩罪數罪併罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00303', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲與A女為夫妻，甲懷疑A有外遇，某日A與其情夫B在B之住宅內發生性行為，甲打破窗戶，入 內趁A、B未及反應之際，拍攝A、B裸體照片。甲不成立何罪？', '["毀損器物罪", "竊錄他人非公開活動罪", "侵入住居罪", "強制罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "60e8b39a1ddb", "answer_pdf_sha1": "3c86136ea7a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
